-- 추가 30개 용어 (총 250개 달성)
INSERT OR IGNORE INTO dictionary (slug, term_ko, term_en, category, summary, description, related_treatment, related_terms, difficulty, is_featured) VALUES
-- 임플란트 1개
('implant-aftercare', '임플란트 수술 후 관리', 'Implant Post-Operative Care', '임플란트', '임플란트 수술 직후 지켜야 할 사항', '수술 후 24시간 내 냉찜질, 부드러운 음식 섭취, 빨대 사용 금지, 격한 운동 자제, 처방 약물 복용 등을 지켜야 합니다. 일반적으로 7~14일 후 실밥을 제거합니다.', 'implant', '임플란트,봉합,회복', 1, 0),

-- 교정 1개
('clear-aligner', '클리어 얼라이너', 'Clear Aligner', '교정', '투명한 맞춤형 교정 장치의 총칭', '인비절라인 외에도 투명교정 시스템을 통칭하는 용어입니다. 3D 스캔 데이터로 제작되며, 2주 간격으로 교체하면서 치아를 이동시킵니다.', 'invisalign', '인비절라인,얼라이너,교정', 1, 0),

-- 보철 6개
('gold-crown', '금 크라운', 'Gold Crown', '보철', '금합금으로 제작한 크라운', '금합금은 치아와 유사한 경도를 가져 대합치(맞물리는 치아)를 손상시키지 않으며, 생체친화성이 뛰어납니다. 내구성이 가장 우수하지만, 색상이 눈에 띄는 단점이 있습니다.', 'crown', '크라운,보철,금속', 1, 0),
('impression', '인상채득 (본뜨기)', 'Dental Impression', '보철', '치아 형태를 기록하는 전통적 방법', '트레이에 인상재(실리콘 등)를 담아 치아에 누르고 굳혀 치아의 3D 형태를 기록하는 방법입니다. 현재는 디지털 구강 스캐너로 대체되는 추세입니다.', NULL, '보철,디지털 인상,구강 스캐너', 1, 0),
('shade-matching', '색조 선택', 'Shade Matching', '보철', '보철물 색상을 자연치아에 맞추는 과정', '크라운, 라미네이트 등 보철물 제작 시 주변 치아와 가장 자연스러운 색을 선택하는 과정입니다. 비타(VITA) 쉐이드 가이드가 표준으로 사용됩니다.', NULL, '크라운,라미네이트,심미', 1, 0),
('bite-adjustment', '교합 조정', 'Bite Adjustment (Occlusal Adjustment)', '보철', '치아의 높낮이를 미세 조정하는 시술', '보철물 장착 후 높은 부분을 미세하게 삭제하여 편안한 교합을 만드는 과정입니다. 교합이 맞지 않으면 턱관절 통증, 치아 통증 등이 발생할 수 있습니다.', NULL, '교합,크라운,보철', 1, 0),
('metal-free', '메탈프리', 'Metal-Free', '보철', '금속을 사용하지 않는 보철 방식', '보철물 제작에 금속을 전혀 사용하지 않는 방식입니다. 올세라믹, 지르코니아 등이 대표적이며, 금속 알레르기 위험이 없고 잇몸 변색이 발생하지 않습니다.', 'crown', '올세라믹,지르코니아,심미', 1, 0),
('veneer', '비니어', 'Veneer', '보철', '치아 앞면에 얇게 부착하는 보철물', '라미네이트와 유사한 개념으로, 치아 앞면에 얇은 세라믹이나 레진 판을 접착하여 색상, 형태, 크기를 개선합니다. 심미적 목적이 주이며, 최소한의 삭제로 진행합니다.', 'cosmetic', '라미네이트,심미,세라믹', 1, 0),

-- 일반 5개
('dental-checkup', '치과 검진', 'Dental Check-up', '일반', '정기적인 구강 건강 검사', '충치, 잇몸 질환, 구강암 등을 조기에 발견하기 위한 정기 검진입니다. 6개월마다 방문하는 것이 이상적이며, 시진, X-ray, 치주 검사 등을 포함합니다.', NULL, '예방,스케일링,정기검진', 1, 0),
('dental-anxiety', '치과 공포증', 'Dental Anxiety', '일반', '치과 치료에 대한 과도한 불안과 공포', '치과 치료 시 과도한 불안, 두려움, 회피 행동을 보이는 상태입니다. 수면 마취(의식 하 진정), 아산화질소 흡입 등으로 편안한 치료가 가능합니다.', NULL, '수면 마취,아산화질소,진정', 1, 0),
('dental-erosion', '치아 침식', 'Dental Erosion', '일반', '산에 의해 치아 표면이 녹는 현상', '산성 음식(탄산음료, 과일주스, 식초), 위산 역류 등에 의해 치아 법랑질이 녹아 얇아지는 현상입니다. 충치와 달리 세균 관여 없이 화학적으로 발생합니다.', NULL, '법랑질,충치,산성', 1, 0),
('halitosis', '구취 (입 냄새)', 'Halitosis', '일반', '입에서 불쾌한 냄새가 나는 증상', '구강 내 세균이 음식 찌꺼기와 죽은 세포를 분해하면서 황화합물을 생성하여 냄새가 납니다. 잇몸병, 설태, 충치, 구강 건조증 등이 원인입니다.', NULL, '잇몸,설태,구강건조증', 1, 0),
('dry-mouth', '구강 건조증', 'Dry Mouth (Xerostomia)', '일반', '침 분비가 줄어 입안이 마르는 상태', '약물 부작용, 자가면역질환, 방사선 치료, 노화 등으로 타액 분비가 감소하여 입안이 건조해지는 상태입니다. 충치와 잇몸병 위험이 크게 증가합니다.', NULL, '타액선,충치,잇몸', 1, 0),

-- 외과 2개
('impacted-tooth', '매복치', 'Impacted Tooth', '외과', '뼈나 잇몸 속에 묻혀 나오지 못한 치아', '정상적으로 맹출하지 못하고 턱뼈나 잇몸 속에 부분 또는 완전히 묻혀 있는 치아입니다. 사랑니가 가장 흔하며, 위치에 따라 수직, 수평, 근심 매복 등으로 분류됩니다.', 'wisdom-tooth', '사랑니,발치,구강외과', 2, 0),
('cyst', '낭종 (물혹)', 'Cyst', '외과', '턱뼈 안에 생기는 액체가 찬 주머니', '치아 뿌리 끝이나 매복치 주변에 발생하는 액체가 찬 병소입니다. 서서히 커지며 주변 뼈를 녹이므로, 발견 시 수술적 적출이 필요합니다.', NULL, '매복치,수술,병리검사', 2, 0),

-- 치주 1개
('gingival-recession', '잇몸 퇴축', 'Gingival Recession', '치주', '잇몸이 아래로 내려가 치아 뿌리가 노출되는 상태', '잇몸이 치아 뿌리 방향으로 내려가 원래 잇몸에 덮여 있던 치아 뿌리가 드러나는 상태입니다. 시린이, 심미 문제를 유발하며, 과도한 칫솔질, 치주질환 등이 원인입니다.', NULL, '시린이,잇몸 이식,치주', 1, 0),

-- 소아 1개
('nitrous-oxide', '아산화질소 (웃음 가스)', 'Nitrous Oxide', '소아', '치과 불안을 줄이는 흡입 진정제', '코 마스크를 통해 흡입하면 불안감이 줄고 편안해지는 가스입니다. "웃음 가스"라 불리며, 소아 환자나 치과 공포증 환자에게 많이 사용됩니다. 효과가 빠르고 회복도 빠릅니다.', NULL, '소아 진정,치과 공포증,마취', 1, 0),

-- 장비 1개
('sterilization', '멸균', 'Sterilization', '장비', '모든 미생물을 완전히 제거하는 과정', '세균, 바이러스, 곰팡이, 포자 등 모든 미생물을 완전히 사멸시키는 과정입니다. 치과에서는 오토클레이브(고압증기 멸균)가 표준이며, 1인 1기구 패킹 시스템이 이상적입니다.', NULL, '오토클레이브,감염 관리,소독', 1, 0),

-- 해부학 4개
('dentin', '상아질', 'Dentin', '해부학', '법랑질 아래에 있는 치아의 주요 구조', '치아의 대부분을 구성하는 조직으로, 법랑질보다 부드럽고 노란색입니다. 미세한 관(상아세관)이 있어 자극이 전달되며, 충치가 상아질에 도달하면 시린 증상이 나타납니다.', NULL, '법랑질,충치,시린이', 2, 0),
('cementum', '백악질', 'Cementum', '해부학', '치아 뿌리를 감싸는 얇은 조직', '치아 뿌리 표면을 덮고 있는 뼈와 유사한 조직입니다. 치주인대를 통해 치아를 치조골에 고정하는 역할을 합니다. 잇몸 퇴축 시 노출되면 충치에 취약해집니다.', NULL, '치주인대,치조골,잇몸 퇴축', 3, 0),
('periodontal-ligament', '치주인대', 'Periodontal Ligament', '해부학', '치아와 치조골을 연결하는 섬유 조직', '치아 뿌리의 백악질과 치조골 사이에 있는 결합 조직입니다. 씹는 힘의 충격을 흡수하고, 치아의 미세한 움직임을 허용합니다. 교정 치료는 이 인대의 리모델링 원리를 이용합니다.', NULL, '치조골,교정,백악질', 3, 0),
('oral-microbiome', '구강 마이크로바이옴', 'Oral Microbiome', '해부학', '입안에 서식하는 미생물 생태계', '구강 내에는 700종 이상의 세균이 공존하며, 이들의 균형이 구강 건강을 좌우합니다. 유익균과 유해균의 균형이 깨지면 충치, 치주질환 등이 발생합니다.', NULL, '충치,치주질환,세균', 2, 0),

-- 보험 1개
('emergency-dental', '치과 응급 진료', 'Emergency Dental Care', '보험', '긴급한 치과 문제 시 즉시 치료', '극심한 치통, 외상으로 인한 치아 파절/탈구, 심한 출혈, 농양 등 긴급한 치과 문제 발생 시 즉시 받는 진료입니다. 대부분 건강보험이 적용됩니다.', NULL, '통증,외상,농양', 1, 0);
